// Generate search queries for finding ICP companies
const config = $input.first().json;
const keywords = config.icp_keywords.split(',').map(k => k.trim());
const regions = config.icp_geography.split(',').map(r => r.trim());

const queries = [];

// Generate targeted search queries
for (const keyword of keywords) {
  for (const region of regions) {
    queries.push({
      query: `"${keyword}" "${region}" site:linkedin.com/company`,
      source: 'linkedin',
      keyword,
      region
    });
    queries.push({
      query: `"${keyword}" "${region}" -site:linkedin.com`,
      source: 'web',
      keyword,
      region
    });
  }
}

// Add industry-specific directories
const directoryQueries = [
  { query: 'coffee importers directory Europe', source: 'directory', keyword: 'directory', region: 'Europe' },
  { query: 'SCA members list specialty coffee', source: 'directory', keyword: 'SCA', region: 'Global' },
  { query: 'coffee buyers wholesale Australia', source: 'directory', keyword: 'wholesale', region: 'Australia' },
  { query: 'coffee trade association members', source: 'directory', keyword: 'trade association', region: 'Global' },
  { query: 'private label coffee brands Europe', source: 'directory', keyword: 'private label', region: 'Europe' },
  { query: 'cafe chain coffee supplier Middle East', source: 'directory', keyword: 'cafe chain', region: 'Middle East' },
  { query: 'green coffee importers list', source: 'directory', keyword: 'importers list', region: 'Global' },
  { query: 'World of Coffee exhibitors list', source: 'directory', keyword: 'WoC exhibitors', region: 'Global' }
];

queries.push(...directoryQueries);

return queries.map(q => ({ json: q }));

// Extract company information from search results
const results = $input.all();
const companies = [];
const seen = new Set();

for (const result of results) {
  const webResults = result.json?.web?.results || [];

  for (const r of webResults) {
    const url = r.url || '';
    const title = r.title || '';
    const description = r.description || '';

    // Extract company name from various patterns
    let companyName = '';
    let website = '';
    let linkedinUrl = '';

    if (url.includes('linkedin.com/company/')) {
      // Extract from LinkedIn
      const match = url.match(/linkedin\.com\/company\/([^/]+)/);
      if (match) {
        companyName = title.replace(/\s*[-|].*$/, '').replace(/\s*\|.*$/, '').trim();
        linkedinUrl = url;
      }
    } else {
      // Extract from web results
      companyName = title.replace(/\s*[-|].*$/, '').replace(/\s*\|.*$/, '').trim();
      website = url;
    }

    if (!companyName || companyName.length < 3) continue;

    const key = companyName.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (seen.has(key)) continue;
    seen.add(key);

    companies.push({
      company_name: companyName,
      website: website,
      linkedin_url: linkedinUrl,
      description: description.substring(0, 300),
      source_query: result.json?.query || 'unknown',
      source_type: result.json?.source || 'web',
      region: result.json?.region || 'unknown',
      found_at: new Date().toISOString()
    });
  }
}

return companies.map(c => ({ json: c }));

// Parse Claude's scoring response and merge with company data
const response = $input.first().json;
const content = response.content?.[0]?.text || '';

// Extract JSON from Claude's response
let scores = [];
try {
  const jsonMatch = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    scores = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  // If parsing fails, return companies without scores
  const prevData = $('Extract Companies').all();
  return prevData.map(item => ({
    json: {
      ...item.json,
      icp_score: 50,
      priority_tier: 'C',
      scoring_error: 'Failed to parse AI scoring'
    }
  }));
}

// Merge scores with company data
const prevCompanies = $('Extract Companies').all().map(i => i.json);
const scoreMap = new Map(scores.map(s => [s.company_name?.toLowerCase(), s]));

const enriched = prevCompanies.map(company => {
  const score = scoreMap.get(company.company_name?.toLowerCase()) || {};
  return {
    json: {
      ...company,
      icp_score: score.icp_score || 50,
      priority_tier: score.priority_tier || 'C',
      scoring_reasoning: score.reasoning || '',
      status: 'scored',
      pipeline_stage: 'company_found'
    }
  };
});

// Sort by ICP score descending, return top companies
return enriched
  .sort((a, b) => (b.json.icp_score || 0) - (a.json.icp_score || 0))
  .filter(c => c.json.icp_score >= 40); // Only keep C tier and above

// Trigger the Org Chart Mapper workflow for Tier A companies first
const companies = $input.all();
return companies.map(c => ({
  json: {
    ...c.json,
    trigger_org_mapper: true,
    contacts_needed: 3,
    target_roles: ['Procurement Head', 'Coffee Buyer', 'Category Manager', 'Head of Purchasing', 'Supply Chain Director', 'Sourcing Manager']
  }
}));
